INSERT INTO [Purch_ Price Model Item] ( [Model Item No_], [Vendor No_], [Starting Date], [Currency Code], [Unit of Measure Code], [Minimum Quantity], [Constant Variable Code], [Variable Code 01], [Variable Code 02], [selling season code], [Ending Date], [Constant Assortment Var_Grp_], [Variable Group 01], [Variable Group 02], [Direct Unit Cost] )
SELECT [Purch_ Price Model Item].[Model Item No_], "VAL A" AS NewVendor, [forms]![principale]![DataSvalutazioneMagazzino] AS NewDate, "" AS NewCurrency, [Purch_ Price Model Item].[Unit of Measure Code], [Purch_ Price Model Item].[Minimum Quantity], [Purch_ Price Model Item].[Constant Variable Code], [Purch_ Price Model Item].[Variable Code 01], [Purch_ Price Model Item].[Variable Code 02], "" AS [Selling Season Code], [Purch_ Price Model Item].[Ending Date], [Purch_ Price Model Item].[Constant Assortment Var_Grp_], [Purch_ Price Model Item].[Variable Group 01], [Purch_ Price Model Item].[Variable Group 02], Round(Val([Direct Unit Cost])*(1-[forms]![principale]![PercentualeSvalutazioneVALA]),2) AS NewDirectUnitCost
FROM (ValutazioneMagazzino_SvalutazioneValA_Select INNER JOIN [Purch_ Price Model Item] ON (ValutazioneMagazzino_SvalutazioneValA_Select.[Model Item No_] = [Purch_ Price Model Item].[Model Item No_]) AND (ValutazioneMagazzino_SvalutazioneValA_Select.[Vendor No_] = [Purch_ Price Model Item].[Vendor No_]) AND (ValutazioneMagazzino_SvalutazioneValA_Select.[MaxDiStarting Date] = [Purch_ Price Model Item].[Starting Date])) INNER JOIN ValutazioneMagazzino_Support_DeterminazioneCodiciGiacenti ON [Purch_ Price Model Item].[Model Item No_] = ValutazioneMagazzino_Support_DeterminazioneCodiciGiacenti.[Model Item No_];

